   997 |   // (X+1) <u X        --> X >u (MAXUINT-1)        --> X == 255
   998 |   // (X+2) <u X        --> X >u (MAXUINT-2)        --> X > 253
   999 |   // (X+MAXUINT) <u X  --> X >u (MAXUINT-MAXUINT)  --> X != 0
